import { NextRequest, NextResponse } from 'next/server'
import { z } from 'zod'
import { generateImage } from '@/lib/ai/generate-image'
import { getApiKey } from '@/lib/settings/api-key'
import { resolveImageProvider } from '@/lib/constants/image-generation'
import { logApiUsage } from '@/lib/ai/usage'
import { AIProviderSchema } from '@/lib/agent/types'

const RequestSchema = z.object({ prompt: z.string().min(10), provider: AIProviderSchema.optional(), aspectRatio: z.enum(['square', 'landscape', 'portrait']).optional() })

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const parsed = RequestSchema.safeParse(body)
    if (!parsed.success) return NextResponse.json({ error: 'Invalid request' }, { status: 400 })
    const preferred = parsed.data.provider ?? 'xai'
    const imageProvider = await resolveImageProvider(preferred)
    if (!imageProvider) return NextResponse.json({ error: 'No API key configured for image generation (xAI, OpenAI, or Google)' }, { status: 400 })
    const apiKey = await getApiKey(imageProvider)
    if (!apiKey) return NextResponse.json({ error: `No API key for ${imageProvider} image generation` }, { status: 400 })
    const result = await generateImage({ provider: imageProvider, apiKey, prompt: parsed.data.prompt, aspectRatio: parsed.data.aspectRatio ?? 'landscape' })
    await logApiUsage({ provider: imageProvider, model: result.model, purpose: `image: ${parsed.data.prompt.slice(0, 40)}`, estimatedCostUsd: result.estimatedCostUsd })
    return NextResponse.json({ image: result.image, provider: result.provider, model: result.model, estimatedCostUsd: result.estimatedCostUsd })
  } catch (error: unknown) {
    console.error('Image generation failed:', error)
    const message = error instanceof Error ? error.message : 'Image generation failed'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { z } from 'zod'
import { callAI } from '@/lib/ai/call-ai'
import { AIProviderSchema } from '@/lib/agent/types'

const RequestSchema = z.object({ provider: AIProviderSchema })

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const parsed = RequestSchema.safeParse(body)
    if (!parsed.success) return NextResponse.json({ error: 'Invalid provider' }, { status: 400 })
    const result = await callAI({ provider: parsed.data.provider, purpose: 'test_connection', temperature: 0, maxTokens: 16, messages: [{ role: 'user', content: 'Reply with exactly: ok' }] })
    return NextResponse.json({ status: 'ok', model: result.model, preview: result.content.slice(0, 50) })
  } catch (error: unknown) {
    const message = error instanceof Error ? error.message : 'Connection failed'
    return NextResponse.json({ error: message }, { status: 400 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { getXaiApiKey } from '@/lib/settings/api-key'

export async function POST(request: NextRequest) {
  let { url } = await request.json()
  if (!url) return NextResponse.json({ error: 'URL is required' }, { status: 400 })
  const apiKey = await getXaiApiKey()
  if (!apiKey) return NextResponse.json({ error: 'XAI_API_KEY is not configured. Add it in Settings or your .env.local file.' }, { status: 500 })
  url = url.trim()
  if (!/^https?:\/\//i.test(url)) url = `https://${url}`
  try {
    const res = await fetch(url, { headers: { 'User-Agent': 'TekMarketingBot/1.0' } })
    if (!res.ok) throw new Error(`Failed to fetch website (status ${res.status})`)
    const html = await res.text()
    const titleMatch = html.match(/<title>(.*?)<\/title>/i)
    const title = titleMatch ? titleMatch[1] : ''
    const textContent = html.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<style[\s\S]*?<\/style>/gi, '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 8000)
    const prompt = `You are an expert brand strategist. Analyze the following website content and extract structured brand information.\n\nWebsite URL: ${url}\nPage Title: ${title}\n\nContent:\n${textContent}\n\nReturn a JSON object with exactly these fields:\n{\n  "companyName": "short company name",\n  "voiceDescription": "detailed 2-4 sentence brand voice and personality (how they speak)",\n  "targetAudience": "clear description of their ideal customer",\n  "productsServices": "main products or services they offer",\n  "keyDifferentiators": "what makes them unique (if obvious)",\n  "primaryGoals": "likely marketing goals based on the site",\n  "toneKeywords": "3-6 tone words",\n  "contentPillars": "suggested content themes"\n}\n\nOnly return valid JSON. Be concise but high quality.`
    const xaiRes = await fetch('https://api.x.ai/v1/chat/completions', { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` }, body: JSON.stringify({ model: 'grok-3', messages: [{ role: 'system', content: 'You are a world-class brand strategist. Always return clean JSON only.' }, { role: 'user', content: prompt }], temperature: 0.4 }) })
    if (!xaiRes.ok) { const errorBody = await xaiRes.text(); console.error('xAI API error:', xaiRes.status, errorBody); throw new Error(`xAI API error (${xaiRes.status}): ${errorBody}`) }
    const xaiData = await xaiRes.json()
    const raw = xaiData.choices?.[0]?.message?.content || '{}'
    let parsed
    try { parsed = JSON.parse(raw.replace(/```json|```/g, '').trim()) } catch { parsed = {} }
    return NextResponse.json({ success: true, data: { companyName: parsed.companyName || title.split('|')[0].trim() || '', voiceDescription: parsed.voiceDescription || '', targetAudience: parsed.targetAudience || '', productsServices: parsed.productsServices || '', keyDifferentiators: parsed.keyDifferentiators || '', primaryGoals: parsed.primaryGoals || '', toneKeywords: parsed.toneKeywords || '', contentPillars: parsed.contentPillars || '', preferredPlatforms: 'X,LinkedIn,Instagram,Email' } })
  } catch (error: any) {
    console.error('Brand analysis error:', error)
    let message = 'Could not analyze the website. Please fill the form manually.'
    if (error.message?.includes('Invalid URL') || error.code === 'ERR_INVALID_URL') message = 'Invalid website URL. Please include https:// or use a valid domain (e.g. example.com)'
    else if (error.message?.includes('Failed to fetch')) message = 'Could not reach that website. Please check the URL or try again later.'
    else if (error.message?.includes('xAI API error')) message = error.message
    return NextResponse.json({ error: message }, { status: 400 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'
import { BrandContextSchema } from '@/lib/agent/types'

export async function GET() {
  try {
    const brand = await prisma.brandContext.findFirst({ where: { isActive: true }, orderBy: { updatedAt: 'desc' } }) ?? await prisma.brandContext.findFirst({ orderBy: { updatedAt: 'desc' } })
    return NextResponse.json({ brand })
  } catch (error) {
    console.error('Failed to load brand:', error)
    return NextResponse.json({ error: 'Failed to load brand context' }, { status: 500 })
  }
}

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const parsed = BrandContextSchema.safeParse(body)
    if (!parsed.success) return NextResponse.json({ error: 'Invalid brand data', details: parsed.error.flatten() }, { status: 400 })
    const data = parsed.data
    const existing = await prisma.brandContext.findFirst()
    let brand
    if (existing) {
      brand = await prisma.brandContext.update({ where: { id: existing.id }, data: { companyName: data.companyName, voiceDescription: data.voiceDescription, targetAudience: data.targetAudience, productsServices: data.productsServices, keyDifferentiators: data.keyDifferentiators ?? null, primaryGoals: data.primaryGoals, contentPillars: data.contentPillars ?? null, preferredPlatforms: data.preferredPlatforms, toneKeywords: data.toneKeywords ?? null, doNotSay: data.doNotSay ?? null } })
    } else {
      brand = await prisma.brandContext.create({ data: { companyName: data.companyName, voiceDescription: data.voiceDescription, targetAudience: data.targetAudience, productsServices: data.productsServices, keyDifferentiators: data.keyDifferentiators ?? null, primaryGoals: data.primaryGoals, contentPillars: data.contentPillars ?? null, preferredPlatforms: data.preferredPlatforms, toneKeywords: data.toneKeywords ?? null, doNotSay: data.doNotSay ?? null } })
    }
    await prisma.activityLog.create({ data: { type: 'BRAND_UPDATED', summary: `Brand context updated for ${data.companyName}`, details: { companyName: data.companyName } } })
    return NextResponse.json({ success: true, brand })
  } catch (error) {
    console.error('Failed to save brand:', error)
    return NextResponse.json({ error: 'Failed to save brand context' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

type RouteContext = { params: Promise<{ id: string }> }

export async function POST(_request: NextRequest, context: RouteContext) {
  const { id } = await context.params
  try {
    const business = await prisma.brandContext.findUnique({ where: { id } })
    if (!business) return NextResponse.json({ error: 'Business not found' }, { status: 404 })
    await prisma.brandContext.updateMany({ data: { isActive: false } })
    const updated = await prisma.brandContext.update({ where: { id }, data: { isActive: true } })
    await prisma.activityLog.create({ data: { type: 'BRAND_UPDATED', summary: `Active business switched to ${updated.companyName}`, details: { companyName: updated.companyName, action: 'activated' } } })
    return NextResponse.json({ success: true, business: updated })
  } catch (error) {
    console.error('Failed to activate business:', error)
    return NextResponse.json({ error: 'Failed to activate business' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'
import { BrandContextSchema } from '@/lib/agent/types'

type RouteContext = { params: Promise<{ id: string }> }

export async function GET(_request: NextRequest, context: RouteContext) {
  const { id } = await context.params
