    if (!business) return NextResponse.json({ error: 'Business not found' }, { status: 404 })
    return NextResponse.json({ business })
  } catch (error) {
    console.error('Failed to load business:', error)
    return NextResponse.json({ error: 'Failed to load business' }, { status: 500 })
  }
}

export async function PUT(request: NextRequest, context: RouteContext) {
  const { id } = await context.params
  try {
    const body = await request.json()
    const parsed = BrandContextSchema.safeParse(body)
    if (!parsed.success) return NextResponse.json({ error: 'Invalid business data', details: parsed.error.flatten() }, { status: 400 })
    const data = parsed.data
    const business = await prisma.brandContext.update({ where: { id }, data: { companyName: data.companyName, voiceDescription: data.voiceDescription, targetAudience: data.targetAudience, productsServices: data.productsServices, keyDifferentiators: data.keyDifferentiators ?? null, primaryGoals: data.primaryGoals, contentPillars: data.contentPillars ?? null, preferredPlatforms: data.preferredPlatforms, toneKeywords: data.toneKeywords ?? null, doNotSay: data.doNotSay ?? null, industry: data.industry ?? null, website: data.website || null, visualStyle: data.visualStyle ?? null, logoDataUrl: data.logoDataUrl ?? null, additionalContext: data.additionalContext ?? null } })
    await prisma.activityLog.create({ data: { type: 'BRAND_UPDATED', summary: `Business profile updated: ${data.companyName}`, details: { companyName: data.companyName, action: 'updated' } } })
    return NextResponse.json({ success: true, business })
  } catch (error) {
    console.error('Failed to update business:', error)
    return NextResponse.json({ error: 'Failed to update business' }, { status: 500 })
  }
}

export async function DELETE(_request: NextRequest, context: RouteContext) {
  const { id } = await context.params
  try {
    const existing = await prisma.brandContext.findUnique({ where: { id } })
    if (!existing) return NextResponse.json({ error: 'Business not found' }, { status: 404 })
    await prisma.brandContext.delete({ where: { id } })
    if (existing.isActive) {
      const next = await prisma.brandContext.findFirst({ orderBy: { updatedAt: 'desc' } })
      if (next) await prisma.brandContext.update({ where: { id: next.id }, data: { isActive: true } })
    }
    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('Failed to delete business:', error)
    return NextResponse.json({ error: 'Failed to delete business' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'
import { BrandContextSchema } from '@/lib/agent/types'

export async function GET() {
  try {
    const businesses = await prisma.brandContext.findMany({
      orderBy: [{ isActive: 'desc' }, { updatedAt: 'desc' }],
    })
    return NextResponse.json({ businesses })
  } catch (error) {
    console.error('Failed to list businesses:', error)
    return NextResponse.json({ error: 'Failed to load businesses' }, { status: 500 })
  }
}

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const parsed = BrandContextSchema.safeParse(body)

    if (!parsed.success) {
      return NextResponse.json(
        { error: 'Invalid business data', details: parsed.error.flatten() },
        { status: 400 }
      )
    }

    const data = parsed.data
    const count = await prisma.brandContext.count()
    const makeActive = body.setActive === true || count === 0

    if (makeActive) {
      await prisma.brandContext.updateMany({ data: { isActive: false } })
    }

    const business = await prisma.brandContext.create({
      data: {
        companyName: data.companyName,
        voiceDescription: data.voiceDescription,
        targetAudience: data.targetAudience,
        productsServices: data.productsServices,
        keyDifferentiators: data.keyDifferentiators ?? null,
        primaryGoals: data.primaryGoals,
        contentPillars: data.contentPillars ?? null,
        preferredPlatforms: data.preferredPlatforms,
        toneKeywords: data.toneKeywords ?? null,
        doNotSay: data.doNotSay ?? null,
        industry: data.industry ?? null,
        website: data.website || null,
        visualStyle: data.visualStyle ?? null,
        logoDataUrl: data.logoDataUrl ?? null,
        additionalContext: data.additionalContext ?? null,
        isActive: makeActive,
      },
    })

    await prisma.activityLog.create({
      data: {
        type: 'BRAND_UPDATED',
        summary: `Business profile created: ${data.companyName}`,
        details: { companyName: data.companyName, action: 'created' },
      },
    })

    return NextResponse.json({ success: true, business })
  } catch (error) {
    console.error('Failed to create business:', error)
    return NextResponse.json({ error: 'Failed to create business' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params
    const body = await request.json().catch(() => ({}))
    const { scheduledFor } = body // optional

    const updated = await prisma.contentItem.update({
      where: { id },
      data: {
        status: scheduledFor ? 'SCHEDULED' : 'APPROVED',
        approvedAt: new Date(),
        approvedBy: 'user',
        scheduledFor: scheduledFor ? new Date(scheduledFor) : new Date(Date.now() + 1000 * 60 * 30), // default: 30 min from now if not specified
      },
    })

    // Log the action
    await prisma.activityLog.create({
      data: {
        type: 'CONTENT_APPROVED',
        summary: `Approved ${updated.platform} ${updated.format.toLowerCase()} (scheduled for ${updated.scheduledFor?.toISOString()})`,
        details: { contentItemId: id, platform: updated.platform, scheduledFor: updated.scheduledFor },
        contentItemId: id,
      },
    })

    return NextResponse.json({ success: true, item: updated })
  } catch (error) {
    console.error('Approve failed:', error)
    return NextResponse.json({ error: 'Failed to approve item' }, { status: 500 })
  }
}
